import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';

function Home() {
  const [clientData, setClientData] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    try {
      const loggedInUser = localStorage.getItem('clientUser');
      if (loggedInUser) {
        setClientData(JSON.parse(loggedInUser));
      }
    } catch (error) {
      console.error("Error parsing user data:", error);
    }
  }, []);

  const handleCardAction = (type) => {
    if (type === 'payments') {
      alert("Redirecting to our Secure Payment Policy...");
    } else if (type === 'students') {
      navigate('/services'); 
    } else if (type === 'delivery') {
      navigate('/contact');
    }
  };

  return (
    <div className="home-page" style={{ fontFamily: "'Poppins', sans-serif", overflowX: 'hidden', backgroundColor: '#ffffff' }}>
      
      {/* 1. Hero Section */}
      <header className="hero-section text-white d-flex align-items-center" 
        style={{ 
          background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
          minHeight: '40vh',
          padding: '40px 0'
        }}>
        <div className="container text-center">
          <h1 className="display-4 fw-bold mb-2">Freelance Hub</h1>
          <p className="lead opacity-75">Nashik's Premier Student Marketplace</p>
        </div>
      </header>

      {/* 2. WhatsApp Sidebar Style Section (As per your image) */}
      <section className="py-5">
        <div className="container">
          <div className="row align-items-center">
            
            {/* Left Sidebar: Vertical Layout like your reference image */}
            <div className="col-auto d-flex flex-column align-items-center py-4 rounded-4 shadow-sm" 
                 style={{ width: '90px', gap: '25px', backgroundColor: '#f9f9f9', border: '1px solid #eee' }}>
              
              {/* Top Icon: Status/Image Icon */}
              <div className="text-muted opacity-50" style={{ cursor: 'pointer' }}>
                <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <rect x="3" y="3" width="18" height="18" rx="2" ry="2"></rect>
                  <circle cx="8.5" cy="8.5" r="1.5"></circle>
                  <polyline points="21 15 16 10 5 21"></polyline>
                </svg>
              </div>

              {/* Bottom: Circular Profile Picture */}
              <div 
                onClick={() => navigate('/profile/1')}
                style={{ 
                  width: '65px', 
                  height: '65px', 
                  cursor: 'pointer',
                  padding: '3px',
                  border: '2px solid #007bff',
                  borderRadius: '50%',
                  overflow: 'hidden',
                  background: '#fff'
                }}
              >
                <img 
                  src="https://freepik.com" 
                  className="rounded-circle w-100 h-100" 
                  style={{ objectFit: 'cover' }} 
                  alt="Freelancer Profile" 
                />
              </div>
            </div>

            {/* Right Side: Freelancer Details */}
            <div className="col ms-4">
               <span className="badge bg-success mb-2">Available Now</span>
               <h3 className="fw-bold mb-1">Rahul Patil</h3>
               <p className="text-muted mb-3">Senior Web Developer • Nashik, MH</p>
               <div className="d-flex gap-2">
                  <button onClick={() => navigate('/profile/1')} className="btn btn-primary rounded-pill px-4 fw-bold">View Profile</button>
                  <Link to="/services" className="btn btn-outline-secondary rounded-pill px-4">Browse Others</Link>
               </div>
            </div>

          </div>
        </div>
      </section>

      {/* 3. Features Section */}
      <section className="py-5 bg-white border-top">
        <div className="container py-4 text-center">
          <div className="row g-4">
            <div className="col-md-4" onClick={() => handleCardAction('payments')} style={{ cursor: 'pointer' }}>
              <div className="p-3 feature-box shadow-sm rounded-4 border">
                <h5 className="fw-bold">🛡️ Secure</h5>
                <p className="text-muted small mb-0">Protected transactions for all users.</p>
              </div>
            </div>
            <div className="col-md-4" onClick={() => handleCardAction('students')} style={{ cursor: 'pointer' }}>
              <div className="p-3 feature-box shadow-sm rounded-4 border">
                <h5 className="fw-bold">🎓 Verified</h5>
                <p className="text-muted small mb-0">Hand-picked student talent.</p>
              </div>
            </div>
            <div className="col-md-4" onClick={() => handleCardAction('delivery')} style={{ cursor: 'pointer' }}>
              <div className="p-3 feature-box shadow-sm rounded-4 border">
                <h5 className="fw-bold">⚡ Fast</h5>
                <p className="text-muted small mb-0">Delivery on your timeline.</p>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 4. Location Section */}
      <section className="py-5 bg-light">
        <div className="container text-center">
          <h5 className="fw-bold mb-4">📍 Visit our Nashik Hub</h5>
          <div className="rounded-4 overflow-hidden shadow-sm mx-auto border border-white border-4" style={{ maxWidth: '900px', height: '350px' }}>
            <iframe
              title="Nashik Map"
              src="https://google.com"
              width="100%" height="100%" style={{ border: 0 }} allowFullScreen="" loading="lazy"></iframe>
          </div>
        </div>
      </section>

      <style>{`
        .feature-box { transition: 0.3s; background: #fff; }
        .feature-box:hover { transform: translateY(-5px); background: #fdfdfd; border-color: #007bff !important; }
      `}</style>

    </div>
  );
}

export default Home;
